import pytest

def test_valid_token_resets_password_and_invalidates_sessions(
    api_client,           # <fixture> base HTTP client for hr-app
    create_employee,      # <fixture> creates employee, yields {email, password, user_id}
    issue_reset_token,    # <fixture> issues fresh token, yields token string
    active_session_cookie # <fixture> logs in and yields session cookie
):
    employee = create_employee()
    old_cookie = active_session_cookie(employee)
    token = issue_reset_token(employee["email"])
    new_password = "V@lid#NewPass1!"

    resp = api_client.post(
        "/password/reset",
        json={"token": token, "password": new_password}
    )
    assert resp.status_code == 200

    login_resp = api_client.post(
        "/auth/login",
        json={"email": employee["email"], "password": new_password}
    )
    assert login_resp.status_code == 200

    guarded = api_client.get(
        "/me",
        cookies={"session": old_cookie}
    )
    assert guarded.status_code == 401

