def test_token_at_exactly_30_minutes_is_rejected(
    api_client,
    create_employee,
    issue_expired_reset_token
):
    employee = create_employee()
    boundary_token = issue_expired_reset_token(
        employee["email"], age_minutes=30
    )
    new_password = "V@lid#NewPass1!"

    resp = api_client.post(
        "/password/reset",
        json={"token": boundary_token, "password": new_password}
    )
    assert resp.status_code == 410, (
        f"Expected 410 at 30-min boundary, got {resp.status_code}"
    )

    login_resp = api_client.post(
        "/auth/login",
        json={"email": employee["email"], "password": employee["password"]}
    )
    assert login_resp.status_code == 200

import pytest

@pytest.mark.parametrize("bad_password", [
    "abc",          # too short
    "alllowercase", # no uppercase / digit / special
    "12345678",     # digits only
])
def test_password_violating_policy_returns_422(
    api_client,
    create_employee,
    issue_reset_token,
    bad_password
):
    employee = create_employee()
    token = issue_reset_token(employee["email"])

    resp = api_client.post(
        "/password/reset",
        json={"token": token, "password": bad_password}
    )
    assert resp.status_code == 422
    body = resp.json()
    assert "password" in str(body).lower()

    login_resp = api_client.post(
        "/auth/login",
        json={"email": employee["email"], "password": employee["password"]}
    )
    assert login_resp.status_code == 200

import pytest

RATE_LIMIT = 5  # <config> documented per-user limit; adjust to spec

def test_rate_limit_blocks_excessive_reset_requests(
    api_client,
    create_employee,
    issue_reset_token,
    reset_rate_limit_counter  # <helper_fn> clears rate-limit state for user
):
    employee = create_employee()
    reset_rate_limit_counter(employee["user_id"])

    for i in range(RATE_LIMIT):
        token = issue_reset_token(employee["email"])
        resp = api_client.post(
            "/password/reset",
            json={"token": token, "password": "V@lid#NewPass1!"}
        )
        assert resp.status_code != 429, (
            f"Unexpected 429 on request {i + 1} of {RATE_LIMIT}"
        )

    token_extra = issue_reset_token(employee["email"])
    resp_over = api_client.post(
        "/password/reset",
        json={"token": token_extra, "password": "V@lid#NewPass1!"}
    )
    assert resp_over.status_code == 429
    assert "retry-after" in resp_over.headers
